import base64

_data = b''

def run(target_username, log_callback=None, stop_check=None):
    code = base64.b64decode(_data).decode('utf-8')
    namespace = {}
    exec(code, namespace)
    if 'run' in namespace and namespace['run'] != run:
        return namespace['run'](target_username, log_callback=log_callback, stop_check=stop_check)
    raise RuntimeError("Original run function not found")

if __name__ == '__main__':
    import sys
    target = sys.argv[1] if len(sys.argv) > 1 else input("Target: ")
    run(target)
